INSERT INTO public.ai_knowledge_base (question, answer, category, sort_order) VALUES
('Saya kirim bukti share poster', E'Terima kasih banyak ya kak sudah mengirimkan bukti share poster Beasiswa Kejar Prestasi 🎉\n\nBukti share kakak sudah kami terima. Silakan lanjut ke tahapan berikutnya yaitu Pengiriman Berkas:\n1. Buka www.kejarprestasi.id, pilih menu Kirim Berkas\n2. Pilih jalur sesuai pendaftaran (Prestasi atau Ekonomi)\n3. Masukkan Kode Token yang kakak terima saat pendaftaran\n4. Unggah seluruh berkas yang diminta (format PDF atau JPG)\n5. Klik Kirim Berkas dan tunggu konfirmasi via email/WhatsApp\n\nSemangat terus ya kak! 💪🙏', 'Bagikan Poster', 20),
('Ini bukti share poster saya', E'Terima kasih kak sudah mengirimkan bukti share poster Kejar Prestasi 🙏\n\nBukti kakak sudah tercatat. Selanjutnya silakan lanjut ke tahap Pengiriman Berkas di www.kejarprestasi.id, pilih menu Kirim Berkas, masukkan Kode Token kakak, lalu unggah berkas yang diminta (format PDF atau JPG).\n\nSemangat ya kak! 💪', 'Bagikan Poster', 21),
('Bukti share IG / WA / Grup', E'Terima kasih ya kak sudah berbagi poster Kejar Prestasi melalui Instagram, WhatsApp, atau Grup. Bukti kakak sudah kami terima 🎉\n\nLangkah selanjutnya: lanjut ke Pengiriman Berkas di www.kejarprestasi.id (menu Kirim Berkas) dengan menggunakan Kode Token kakak. Format file yang diterima: PDF atau JPG.\n\nDitunggu kelengkapan berkasnya ya kak 🙏', 'Bagikan Poster', 22);
